# Re-fetch Prism from cdnjs and rebuild prism.min.js.
# Run from anywhere; writes into the script's own directory.
# Locus bundles Prism so the chat WebView can highlight code offline
# (no CDN dependency = "local-first" stays true).

$ErrorActionPreference = 'Stop'
$out = $PSScriptRoot
$ver = '1.29.0'
$base = "https://cdnjs.cloudflare.com/ajax/libs/prism/$ver"

# Order matters - dependencies must load before dependents.
$order = @(
    'prism-core.min.js',
    'prism-markup.min.js',
    'prism-clike.min.js',
    'prism-markup-templating.min.js',
    'prism-css.min.js',
    'prism-c.min.js',
    'prism-cpp.min.js',
    'prism-cmake.min.js',
    'prism-csharp.min.js',
    'prism-java.min.js',
    'prism-javascript.min.js',
    'prism-typescript.min.js',
    'prism-jsx.min.js',
    'prism-tsx.min.js',
    'prism-rust.min.js',
    'prism-go.min.js',
    'prism-python.min.js',
    'prism-ruby.min.js',
    'prism-php.min.js',
    'prism-bash.min.js',
    'prism-json.min.js',
    'prism-yaml.min.js',
    'prism-markdown.min.js',
    'prism-swift.min.js',
    'prism-kotlin.min.js',
    'prism-diff.min.js',
    'prism-sql.min.js',
    'prism-powershell.min.js',
    'prism-xml-doc.min.js'
)

$tmp = Join-Path $out '_tmp'
New-Item -ItemType Directory -Path $tmp -Force | Out-Null

foreach ($name in $order) {
    $url = if ($name -eq 'prism-core.min.js') { "$base/components/$name" } else { "$base/components/$name" }
    Invoke-WebRequest -Uri $url -OutFile (Join-Path $tmp $name) -UseBasicParsing
}

# Two CSS themes (light + dark).
Invoke-WebRequest -Uri "$base/themes/prism.min.css"          -OutFile (Join-Path $out 'prism.min.css')          -UseBasicParsing
Invoke-WebRequest -Uri "$base/themes/prism-tomorrow.min.css" -OutFile (Join-Path $out 'prism-tomorrow.min.css') -UseBasicParsing

$sb = New-Object System.Text.StringBuilder
[void]$sb.AppendLine("/* Locus: bundled Prism $ver - core + $($order.Count - 1) language plugins. Generated by third_party/prism/build-bundle.ps1; do not edit by hand. */")
foreach ($f in $order) {
    [void]$sb.AppendLine("/* === $f === */")
    [void]$sb.AppendLine((Get-Content (Join-Path $tmp $f) -Raw))
}
# Write without BOM - PS 5.1's Set-Content -Encoding UTF8 prepends one, which
# is technically tolerated mid-page by JS engines but looks ugly and breaks
# byte-for-byte diffs against upstream.
$utf8NoBom = New-Object System.Text.UTF8Encoding $false
[System.IO.File]::WriteAllText((Join-Path $out 'prism.min.js'), $sb.ToString(), $utf8NoBom)

Remove-Item $tmp -Recurse -Force
Write-Host "Wrote prism.min.js ($((Get-Item (Join-Path $out 'prism.min.js')).Length) bytes)"
